long long solve(std::vector<long long> prices, std::vector<long long> strategy, long long k) {
    int n = prices.size();
    long long original_profit = 0;
    for (int i = 0; i < n; ++i) {
        original_profit += strategy[i] * prices[i];
    }
    int m = k / 2;
    std::vector<long long> prefixA(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefixA[i + 1] = prefixA[i] + (-strategy[i] * prices[i]);
    }
    std::vector<long long> prefixB(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefixB[i + 1] = prefixB[i] + ((1 - strategy[i]) * prices[i]);
    }
    long long max_delta = -1e18;
    for (int i = 0; i <= n - k; ++i) {
        long long sumA = prefixA[i + m] - prefixA[i];
        int b_start = i + m;
        int b_end = i + k - 1;
        long long sumB = prefixB[b_end + 1] - prefixB[b_start];
        long long delta = sumA + sumB;
        if (delta > max_delta) {
            max_delta = delta;
        }
    }
    return original_profit + std::max(max_delta, 0LL);
}

